mapper.select:
SELECT cm.id as MEMBER_ID, cm.user_id as USER_ID, u.nickname as NICKNAME, NVL(us.total_score, 12) as BRIX, cm.role as ROLE, cm.joined_at as JOINED_AT, cm.privilege_status as STATUS, cm.deposit_status as DEPOSIT_STATUS, cm.last_support_paid_at as LAST_SUPPORT_PAID_AT, u.profile_image_url as PROFILE_IMAGE FROM woorido.challenge_members cm JOIN woorido.users u ON cm.user_id = u.id LEFT JOIN woorido.user_scores us ON us.user_id = cm.user_id WHERE cm.challenge_id = #{challengeId}
AND cm.privilege_status = #{status}
ORDER BY CASE WHEN cm.role = 'LEADER' THEN 1 ELSE 2 END, cm.joined_at ASC

mapper.update:
UPDATE woorido.challenge_members
SET auto_pay_enabled = #{autoPayEnabled}
WHERE user_id = #{userId} AND challenge_id = #{challengeId}

UPDATE woorido.challenge_members
SET role = #{newRole, jdbcType=VARCHAR}
WHERE id = #{memberId, jdbcType=VARCHAR}
  AND challenge_id = #{challengeId, jdbcType=VARCHAR}

mapper.select:
SELECT privilege_status
FROM woorido.challenge_members
WHERE challenge_id = #{challengeId} AND user_id = #{userId}

mapper.update:
UPDATE woorido.challenge_members
SET deposit_status = #{depositStatus}
WHERE challenge_id = #{challengeId} AND user_id = #{userId}
